from typing import List
from sortedcontainers import SortedList

def contains_nearby_almost_duplicate(nums: List[int], index_diff: int, value_diff: int) -> bool:
    window = SortedList()
    for i, x in enumerate(nums):
        # Find leftmost value >= x - value_diff
        pos = window.bisect_left(x - value_diff)
        if pos < len(window) and window[pos] <= x + value_diff:
            return True
        window.add(x)
        if i >= index_diff:
            window.remove(nums[i - index_diff])
    return False
